<?php require_once __DIR__.'/../includes/functions.php'; require_once __DIR__.'/../includes/db.php'; require_admin(); $error=''; if($_SERVER['REQUEST_METHOD']==='POST'){ if(!verify_csrf($_POST['csrf_token']??null)){ $error='Invalid token'; } else { try{$st=db()->prepare('INSERT INTO admins (name,username,email,password_hash,role,status) VALUES (?,?,?,?,?,?)'); $st->execute([post_value('name'),post_value('username'),post_value('email'),password_hash(post_value('password'),PASSWORD_DEFAULT),post_value('role')?:'admin','active']); redirect('users.php');}catch(Exception $e){$error='Unable to create admin. Username or email may already exist.';} }} include 'partials/header.php'; include 'partials/sidebar.php'; ?><h2 class="mb-4 text-3xl font-black">Add Admin User</h2><?php if($error):?><p class="mb-4 rounded bg-red-100 p-3 text-red-700"><?=e($error)?></p><?php endif;?><form method="post" class="max-w-xl rounded-2xl bg-white p-6 shadow"><input type="hidden" name="csrf_token" value="<?=e(csrf_token())?>"><input name="name" required class="mb-3 w-full rounded border p-3" placeholder="Name"><input name="username" required class="mb-3 w-full rounded border p-3" placeholder="Username"><input type="email" name="email" required class="mb-3 w-full rounded border p-3" placeholder="Email"><input name="role" class="mb-3 w-full rounded border p-3" value="admin"><input type="password" name="password" required minlength="8" class="mb-4 w-full rounded border p-3" placeholder="Password"><button class="rounded bg-slate-950 px-5 py-3 font-bold text-white">Create Admin</button></form><?php include 'partials/footer.php'; ?>
